    { name: { en: 'Parsley', ro: 'patrunjel', ru: 'петрушка', es: 'perejil' }, measure: 'Handful' },
    { name: { en: 'Haricot Beans', ro: 'fasole alba', ru: 'белая фасоль', es: 'alubias blancas' }, measure: '400g' },
    { name: { en: 'Breadcrumbs', ro: 'pesmet', ru: 'панировочные сухари', es: 'pan rallado' }, measure: '2 tblsp' },
    { name: { en: 'Oil', ro: 'ulei', ru: 'масло', es: 'aceite' }, measure: 'drizzle' },
    { name: { en: 'Bread', ro: 'paine', ru: 'хлеб', es: 'pan' }, measure: 'to serve' },
    { name: { en: 'Broccoli', ro: 'broccoli', ru: 'брокколи', es: 'brocoli' }, measure: 'to serve' }
