    ingredients: [
    { name: { en: 'Pork Back Ribs', ro: 'coaste de porc', ru: 'свиные рёбрышки', es: 'costillas de cerdo' }, measure: '1kg' },
    { name: { en: 'Bay Leaves', ro: 'frunze de dafin', ru: 'лавровые листья', es: 'hojas de laurel' }, measure: '2' },
    { name: { en: 'Dried white beans', ro: 'fasole alba uscata', ru: 'сушёная белая фасоль', es: 'alubias blancas secas' }, measure: '1 tablespoon' },
    { name: { en: 'Carrots', ro: 'morcovi', ru: 'морковь', es: 'zanahorias' }, measure: '1 large' },
    { name: { en: 'Onion', ro: 'ceapa', ru: 'лук', es: 'cebolla' }, measure: '1 sliced' },
    { name: { en: 'Garlic Clove', ro: 'catel de usturoi', ru: 'зубчик чеснока', es: 'diente de ajo' }, measure: '3 sliced thinly' },
    { name: { en: 'Red Pepper', ro: 'ardei rosu', ru: 'красный перец', es: 'pimiento rojo' }, measure: '1 chopped' },
    { name: { en: 'Red Chilli', ro: 'ardei iute rosu', ru: 'красный чили', es: 'chile rojo' }, measure: '2 chopped' },
    { name: { en: 'Beetroot', ro: 'sfecla', ru: 'свёкла', es: 'remolacha' }, measure: '2' },
    { name: { en: 'Potatoes', ro: 'cartofi', ru: 'картофель', es: 'papas' }, measure: '3 chopped' },
    { name: { en: 'Tomato Puree', ro: 'piure de rosii', ru: 'томатное пюре', es: 'pure de tomate' }, measure: '3  tablespoons' },
    { name: { en: 'White Cabbage', ro: 'varza alba', ru: 'белокочанная капуста', es: 'repollo blanco' }, measure: '1/2' },
    { name: { en: 'Parsley', ro: 'patrunjel', ru: 'петрушка', es: 'perejil' }, measure: 'Handful' },
    { name: { en: 'Dill', ro: 'marar', ru: 'укроп', es: 'eneldo' }, measure: 'Handful' },
    { name: { en: 'Sour Cream', ro: 'smantana', ru: 'сметана', es: 'crema agria' }, measure: '300g' }
    ],
